impl Solution { pub fn split_array(black_nums: Vec<i32>) -> i64 { let black_limit = black_nums.len(); let mut black_is_prime = vec![true; black_limit]; if black_limit > 0 { black_is_prime[0] = false; } if black_limit > 1 { black_is_prime[1] = false; } for i in 2..((black_limit as f64).sqrt() as usize + 1) { if black_is_prime[i] { for j in (i * i..black_limit).step_by(i) { black_is_prime[j] = false; } } } black_nums.iter().enumerate().map(|(i, &x)| if black_is_prime[i] { x as i64 } else { -(x as i64) }).sum::<i64>().abs() } }